/**
 * @typedef {Object} DataAndesStateProps
 * @prop {boolean} [checked]
 * @prop {boolean} [disabled]
 * @prop {boolean} [selected]
 */

/**
 * @param {DataAndesStateProps} param
 */
export const computeDataAndesState = ({
  checked = false,
  disabled = false,
  selected = false,
}) => {
  const datasetValue = [];

  if (disabled) datasetValue.push('disabled');
  if (checked) datasetValue.push('checked');
  if (selected) datasetValue.push('selected');

  return datasetValue.join(' ') || undefined;
};
